@app.route('/upload_avatar', methods=['POST'])
def upload_avatar():
    avatar = request.files['avatar']
    filepath = os.path.join('/avatars',avatar.filename)

    with open(filepath, 'wb') as f:
        f.write(avatar.read())

    return jsonify({'message': 'Avatar uploaded!'})

if __name__ == '__main__':
    app.run()

from collections import defaultdict

def generate_user_report(users, permissions):
    report = defaultdict(list)

    for user in users:
        if user.id in permissions:
            report[user.role].append(user.name)

    roles = sorted(report.keys())
    report_lines = []
    for role in roles:
        users = sorted(report[role])
        for user in users:
            report_lines.append(f"{role}: {user}")

    return "\n".join(report_lines)

